		if ( ds_collMoney.NameValue(row,"crcCd") != "<%=ACConstants.KRW%>" ) {
			if (colid == "remainAmtFcrc") {
				ds_collMoney.NameValue(row,"remainAmt") = Math.round(ds_collMoney.NameValue(row,"remainAmtFcrc") * ds_collMoney.NameValue(row,"exchRt"));
