            if (columnIndex == 12) {
				ds_collMoney.setCellData(row,"remainAmt", Math.round(Number(ds_collMoney.getCellData(row,"remainAmtFcrc")) * Number(ds_collMoney.getCellData(row,"exchRt"))));
			}
		}
    }
};

